    if any(c * 3 in pw for c in string.ascii_letters + string.digits + "!@#$%^&*()-_+="):
        violations.append('repeat')

    # Check sequence (three consecutive ascending digits)
    import re
    if re.search(r'(\d)(\d)(\d)', pw):
        # Extract all 3-digit sequences and check if ascending
        for match in re.finditer(r'(\d)(\d)(\d)', pw):
            digits = match.group()
            if int(digits[0]) < int(digits[1]) < int(digits[2]):
