def parse_csv_line(line):
    if not line:
        return ['']

    fields = []
    start_idx = 0
    length = len(line)

    while start_idx < length:
        if line[start_idx] == '"':
            # Start of a quoted field
            start_idx += 1
            end_idx = start_idx
            while end_idx < length:
                if line[end_idx] == '"':
                    # Check for escaped quote
                    if end_idx + 1 < length and line[end_idx + 1] == '"':
                        # Escaped quote, consume both
                        end_idx += 2
                    else:
                        # End of quoted field
                        end_idx += 1
                        break
                else:
                    end_idx += 1

            # Check for unterminated quoted field
            if end_idx == len(line) or line[end_idx] != ',':
                # Unterminated quoted field
                raise ValueError("Unterminated quoted field")

            # After closing quote, must be comma or end of line
            if end_idx < length and line[end_idx] != ',':
                raise ValueError("Non-comma character after closing quote")

            # Move start_idx to after the closing quote
            start_idx = end_idx + 1

            # Consume the comma if present
            if start_idx < length and line[start_idx] == ',':
                start_idx += 1
        else:
            # Unquoted field
            end_idx = start_idx
            while end_idx < length and line[end_idx] != ',':
                end_idx += 1

            # Check for stray double quote inside unquoted field
            if end_idx < length and line[end_idx] == '"':
                raise ValueError("Stray double quote inside unquoted field")

            # After unquoted field, must be comma or end of line
            if end_idx < length and line[end_idx] != ',':
                raise ValueError("Non-comma character after unquoted field")

            fields.append(line[start_idx:end_idx])
            start_idx = end_idx + 1

    # If the line ended with a comma, we have an extra empty field to add
    if line and line[-1] == ',':
        fields.append('')

    return fields

