def reduce_slope(dx, dy):
    # Handle zero cases
    if dx == 0 and dy == 0:
        return (0, 0)
    if dx == 0:
        return (0, 1)
    if dy == 0:
        return (1, 0)

    # Compute GCD
    common = gcd(abs(dx), abs(dy))
