def max_points_on_line(points):
    if not points:
        return 0
    if len(points) == 1:
        return 1

    max_points = 1

    n = len(points)

    for i in range(n):
        xi, yi = points[i]
        slope_counts = {}
        duplicates = 0

        for j in range(i + 1, n):
            xj, yj = points[j]

            if xj == xi and yj == yi:
                duplicates += 1
                continue

            dx = xj - xi
            dy = yj - yi

            reduced = reduce_slope(dx, dy)

            if reduced in slope_counts:
                slope_counts[reduced] += 1
            else:
                slope_counts[reduced] = 1

        # The number of points on the line with the most common slope
        # is the count for that slope plus the duplicates (points identical to points[i])
        current_max = duplicates
        for count in slope_counts.values():
            current_max = max(current_max, count + duplicates)

        max_points = max(max_points, current_max)

    return max_points
